Build the server-side cron script that fires the daily 'Kitchen check-in time' push notification and wire it into main-cron.ts.

NEW FILE: src/server/instrumentation/cron/scripts/send-review-reminders.ts

The script follows the same pattern as the existing check-expiring-items.ts in the same directory.

FULL LOGIC:

  import { db } from '@/server/db';
  import { getDaysUntilExpiration } from '@/utils/expiration';
  import { NotificationService } from '@/server/services/NotificationService';
  import type { Item, ItemType } from '@/generated/prisma/client';

  function startOfToday(): Date {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    return d;
  }

  export async function sendReviewReminders() {
    const notificationService = new NotificationService();

    // Only target users who have push subscriptions and haven't reviewed today
    const users = await db.user.findMany({
      where: {
        pushSubscriptions: { some: {} },
        OR: [
          { lastReviewedAt: null },
          { lastReviewedAt: { lt: startOfToday() } }
        ]
      },
      include: {
        items: {
          where: { status: { in: ['BAD', 'OLD', 'FRESH'] } },
          include: { itemTypes: { select: { id: true, name: true, suggested_life_span_seconds: true } } }
        },
        preferences: false  // preferences are a JSON column, access via user.preferences cast
      }
    });

    for (const user of users) {
      // Check reviewReminderEnabled preference (defaults to true)
      const prefs = (user.preferences as { reviewReminderEnabled?: boolean }) ?? {};
      if (prefs.reviewReminderEnabled === false) continue;

      // Filter to actual at-risk items (FRESH items must be within 3 days)
      const atRiskItems = (user.items as (Item & { itemTypes: ItemType[] })[]).filter(item =>
        item.status === 'BAD' ||
        item.status === 'OLD' ||
        (item.status === 'FRESH' && getDaysUntilExpiration(item) <= 3)
      );
      if (atRiskItems.length === 0) continue;

      // Dedup: skip if already sent a REVIEW_REMINDER today
      const alreadySent = await db.notification.findFirst({
        where: { userId: user.id, type: 'REVIEW_REMINDER', createdAt: { gte: startOfToday() } }
      });
      if (alreadySent) continue;

      // Build notification body (list up to 2 item names)
      const itemNames = atRiskItems.slice(0, 2).map(i => i.itemTypes[0]?.name ?? i.name);
      const remainder = atRiskItems.length - 2;
      const itemsList = remainder > 0
        ? 
        : itemNames.join(' and ');
      const body = ;
      const title = '🥦 Kitchen check-in time';

      // Record in DB (so dedup works and it shows in NotificationBell)
      await db.notification.create({
        data: {
          userId: user.id,
          type: 'REVIEW_REMINDER',
          title,
          message: body,
          metadata: { atRiskCount: atRiskItems.length, itemNames: itemNames }
        }
      });

      // Send push notification
      await notificationService.sendPush({
        userId: user.id,
        title,
        body,
        data: { type: 'AT_RISK_REVIEW', tag: 'at-risk-review' }
      });

      console.log('🥦 Sent review reminder to user', user.id, '—', atRiskItems.length, 'at-risk items');
    }
  }

WIRE INTO main-cron.ts:
Add a new cron.schedule call below the existing expiring items checker:

  import { sendReviewReminders } from './scripts/send-review-reminders';

  // Daily at 9 AM server time
  cron.schedule('0 9 * * *', async () => {
    console.log('🥦 Sending daily review reminders...');
    try {
      await sendReviewReminders();
